class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word: str) -> bool:
        node = self.root
        for char in word:
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

if __name__ == '__main__':
    trie = Trie()
    trie.insert("apple")
    trie.insert("app")
    trie.insert("apricot")
    trie.insert("banana")

    print(f"'apple' search result: {trie.search('apple')}")     # True
    print(f"'app' search result: {trie.search('app')}")         # True
    print(f"'apricot' search result: {trie.search('apricot')}") # True
    print(f"'banana' search result: {trie.search('banana')}")   # True
    print(f"'appl' search result: {trie.search('appl')}")       # False (prefix, but not a full word)
    print(f"'orange' search result: {trie.search('orange')}")   # False
    print(f"'application' search result: {trie.search('application')}") # False
